const input = $('Called by Agent').first().json;
try {
  const raw = $input.first().json.content[0].text;
  const cleaned = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const content = JSON.parse(cleaned);
  return [{ json: {
    status: 'completed',
    workflow: '02_marketing_social_content',
    platform: input.platform || input.parameters?.platform || 'instagram',
    topic: input.topic || input.parameters?.topic || 'swimming lessons',
    content,
    completedAt: new Date().toISOString()
  } }];
} catch (e) {
  const raw = $input.first().json.content?.[0]?.text || 'No content';
  return [{ json: {
    status: 'completed',
    workflow: '02_marketing_social_content',
    content_raw: raw,
    parse_note: 'Response was not valid JSON, returning raw text',
    completedAt: new Date().toISOString()
  } }];
}
